import {
  Entity,
  Column,
  PrimaryGeneratedColumn,
  CreateDateColumn,
  ManyToOne,
  JoinColumn,
  Index,
} from 'typeorm';
import { ProjectRequestEntity } from './project-request.entity';
import { UserEntity } from './user.entity';

export enum ProposalStatus {
  PENDING = 'PENDING',
  INVITED = 'INVITED',
  ACCEPTED = 'ACCEPTED',
  REJECTED = 'REJECTED',
}

@Entity('broker_proposals')
@Index(['requestId', 'brokerId'], { unique: true })
export class BrokerProposalEntity {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column()
  requestId: string;

  @Column()
  brokerId: string;

  @Column({ type: 'text', nullable: true })
  coverLetter: string;

  @Column({
    type: 'enum',
    enum: ProposalStatus,
    default: ProposalStatus.PENDING,
  })
  status: ProposalStatus;

  @CreateDateColumn()
  createdAt: Date;

  // Relations
  @ManyToOne(() => ProjectRequestEntity, (request) => request.brokerProposals, {
    onDelete: 'CASCADE',
  })
  @JoinColumn({ name: 'requestId' })
  request: ProjectRequestEntity;

  @ManyToOne(() => UserEntity, (user) => user.brokerProposals, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'brokerId' })
  broker: UserEntity;
}

import {
  Entity,
  Column,
  PrimaryGeneratedColumn,
  CreateDateColumn,
  ManyToOne,
  JoinColumn,
  OneToMany,
  OneToOne,
} from 'typeorm';
import { UserEntity } from './user.entity';
import type { ProjectSpecEntity } from './project-spec.entity';

export enum RequestStatus {
  PUBLIC_DRAFT = 'PUBLIC_DRAFT',
  PRIVATE_DRAFT = 'PRIVATE_DRAFT',
  BROKER_ASSIGNED = 'BROKER_ASSIGNED',
  SPEC_APPROVED = 'SPEC_APPROVED',
  CONTRACT_PENDING = 'CONTRACT_PENDING',
  HIRING = 'HIRING',
  CONVERTED_TO_PROJECT = 'CONVERTED_TO_PROJECT',

  IN_PROGRESS = 'IN_PROGRESS',
  COMPLETED = 'COMPLETED',
  CANCELED = 'CANCELED',

  DRAFT = 'DRAFT',
  PENDING = 'PENDING',
  PENDING_SPECS = 'PENDING_SPECS',
  PROCESSING = 'PROCESSING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED',
  CANCELLED = 'CANCELLED',
  SPEC_SUBMITTED = 'SPEC_SUBMITTED',
}

@Entity('project_requests')
export class ProjectRequestEntity {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column({ name: 'clientId' })
  clientId: string;

  @Column({ type: 'varchar', length: 255 })
  title: string;

  @Column({ type: 'text' })
  description: string;

  @Column({ name: 'budgetRange', type: 'varchar', nullable: true })
  budgetRange: string;

  @Column({ name: 'intendedTimeline', type: 'varchar', nullable: true })
  intendedTimeline: string;

  @Column({ name: 'techPreferences', type: 'varchar', nullable: true })
  techPreferences: string;

  @Column({
    type: 'enum',
    enum: RequestStatus,
    default: RequestStatus.PENDING,
  })
  status: RequestStatus;

  @Column({ name: 'brokerId', nullable: true })
  brokerId: string;

  @CreateDateColumn({ name: 'createdAt' })
  createdAt: Date;

  // Relations
  @ManyToOne(() => UserEntity, (user) => user.clientRequests, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'clientId' })
  client: UserEntity;

  @ManyToOne(() => UserEntity, (user) => user.brokerRequests, { onDelete: 'SET NULL' })
  @JoinColumn({ name: 'brokerId' })
  broker: UserEntity;

  @OneToMany('ProjectRequestAnswerEntity', 'request')
  answers: any[];

  @OneToMany('ProjectRequestProposalEntity', 'request')
  proposals: any[];

  @OneToOne('ProjectSpecEntity', 'request')
  spec: ProjectSpecEntity;

  @OneToMany('BrokerProposalEntity', 'request')
  brokerProposals: any[];
}

import { Entity, Column, PrimaryGeneratedColumn, OneToMany } from 'typeorm';
import { WizardOptionEntity } from './wizard-option.entity';
import { ProjectRequestAnswerEntity } from './project-request-answer.entity';

@Entity('wizard_questions')
export class WizardQuestionEntity {
  @PrimaryGeneratedColumn()
  id: number;

  @Column({ type: 'varchar', unique: true })
  code: string;

  @Column({ type: 'text' })
  label: string;

  @Column({ name: 'help_text', type: 'text', nullable: true })
  helpText: string;

  @Column({ name: 'input_type', type: 'varchar', nullable: true })
  inputType: string;

  @Column({ name: 'is_active', type: 'boolean', default: true })
  isActive: boolean;

  @Column({ name: 'sort_order', type: 'int', nullable: true })
  sortOrder: number;

  @Column({ name: 'created_at', type: 'timestamp', default: () => 'NOW()' })
  createdAt: Date;

  // Relations
  @OneToMany(() => WizardOptionEntity, (option) => option.question)
  options: WizardOptionEntity[];

  @OneToMany(() => ProjectRequestAnswerEntity, (answer) => answer.question)
  answers: ProjectRequestAnswerEntity[];
}

import { BadRequestException, Injectable, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { DataSource, EntityManager, In, LessThan, MoreThan, Repository } from 'typeorm';

import {
  AutoScheduleRuleEntity,
  CalendarEventEntity,
  EventStatus,
  EventType,
  UserEntity,
  UserRole,
} from 'src/database/entities';
import {
  EventParticipantEntity,
  ParticipantRole,
  ParticipantStatus,
} from 'src/database/entities/event-participant.entity';
import {
  AvailabilityType,
  UserAvailabilityEntity,
} from 'src/database/entities/user-availability.entity';
import { EventRescheduleRequestEntity, RescheduleRequestStatus } from 'src/database/entities';
import { StaffWorkloadEntity } from 'src/database/entities/staff-workload.entity';
import { CalendarService, FindAvailableSlotsInput } from './calendar.service';

const DEFAULT_RESPONSE_DEADLINE_HOURS = 24;
const DEFAULT_RESCHEDULE_WINDOW_DAYS = 7;
const DEFAULT_MIN_RESCHEDULE_NOTICE_HOURS = 2;
const AUTO_RESCHEDULE_LIMIT = 2;
const ACTIVE_EVENT_STATUSES = [
  EventStatus.SCHEDULED,
  EventStatus.PENDING_CONFIRMATION,
  EventStatus.IN_PROGRESS,
  EventStatus.RESCHEDULING,
];
const BUSY_AVAILABILITY_TYPES = [
  AvailabilityType.BUSY,
  AvailabilityType.OUT_OF_OFFICE,
  AvailabilityType.DO_NOT_DISTURB,
];

export interface AutoScheduleEventInput {
  eventType: EventType;
  title: string;
  organizerId: string;
  participantIds: string[];
  requiredParticipantIds?: string[];
  dateRange: { start: Date; end: Date };
  description?: string;
  durationMinutes?: number;
  complexity?: 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL';
  referenceType?: string;
  referenceId?: string;
  preferredSlots?: Array<{ start: Date; end: Date }>;
  userTimezones?: Record<string, string>;
  autoScheduleRuleId?: string;
  previousEventId?: string;
  rescheduleCount?: number;
}

export interface AutoScheduleResult {
  manualRequired: boolean;
  reason?: string;
  selectedSlot?: { start: Date; end: Date };
  event?: CalendarEventEntity;
  participants?: EventParticipantEntity[];
  suggestedRange?: { start: Date; end: Date };
}

export interface RescheduleResult {
  manualRequired: boolean;
  reason?: string;
  event?: CalendarEventEntity;
  participants?: EventParticipantEntity[];
}

@Injectable()
export class AutoScheduleService {
  private readonly logger = new Logger(AutoScheduleService.name);

  constructor(
    @InjectRepository(AutoScheduleRuleEntity)
    private readonly ruleRepository: Repository<AutoScheduleRuleEntity>,
    @InjectRepository(CalendarEventEntity)
    private readonly calendarRepository: Repository<CalendarEventEntity>,
    @InjectRepository(EventParticipantEntity)
    private readonly participantRepository: Repository<EventParticipantEntity>,
    @InjectRepository(UserAvailabilityEntity)
    private readonly availabilityRepository: Repository<UserAvailabilityEntity>,
    @InjectRepository(EventRescheduleRequestEntity)
    private readonly rescheduleRepository: Repository<EventRescheduleRequestEntity>,
    private readonly calendarService: CalendarService,
    private readonly dataSource: DataSource,
  ) {}

  async autoScheduleEvent(input: AutoScheduleEventInput): Promise<AutoScheduleResult> {
    if (!input.participantIds || input.participantIds.length === 0) {
      throw new BadRequestException('participantIds is required');
    }

    const rule = await this.resolveRule(input.eventType, input.autoScheduleRuleId);
    const durationMinutes =
      input.durationMinutes ||
      rule?.defaultDurationMinutes ||
      this.calendarService.estimateEventDuration(input.eventType, input.complexity);

    const participantIds = Array.from(new Set([input.organizerId, ...input.participantIds]));
    const requiredIds = input.requiredParticipantIds?.length
      ? Array.from(new Set(input.requiredParticipantIds))
      : participantIds;

    const slotInput: FindAvailableSlotsInput = {
      userIds: participantIds,
      durationMinutes,
      dateRange: input.dateRange,
      constraints: rule
        ? {
            workingHoursStart: rule.workingHoursStart,
            workingHoursEnd: rule.workingHoursEnd,
            workingDays: rule.workingDays,
            bufferMinutes: rule.bufferMinutes,
            lunchStart: rule.lunchStartTime,
            lunchEnd: rule.lunchEndTime,
            avoidLunchHours: rule.avoidLunchHours,
            maxEventsPerStaffPerDay: rule.maxEventsPerStaffPerDay,
          }
        : undefined,
      userTimezones: input.userTimezones,
      preferredSlots: input.preferredSlots,
    };

    const availableSlots = await this.calendarService.findAvailableSlots(slotInput);
    if (availableSlots.slots.length === 0) {
      return {
        manualRequired: true,
        reason: availableSlots.noSlotsReason || 'No available slots found',
        suggestedRange: this.widenRange(input.dateRange),
      };
    }

    return this.dataSource.transaction(async (manager) => {
      await this.acquireSchedulingLocks(manager, participantIds);

      const selectedSlot = await this.pickFirstAvailableSlot(
        manager,
        availableSlots.slots,
        participantIds,
      );

      if (!selectedSlot) {
        return {
          manualRequired: true,
          reason: 'No available slots after conflict check',
          suggestedRange: this.widenRange(input.dateRange),
        };
      }

      const responseDeadline = this.calculateResponseDeadline(
        selectedSlot.start,
        rule?.minRescheduleNoticeHours,
      );

      const calendarRepo = manager.getRepository(CalendarEventEntity);
      const participantRepo = manager.getRepository(EventParticipantEntity);
      const availabilityRepo = manager.getRepository(UserAvailabilityEntity);

      const event = calendarRepo.create({
        type: input.eventType,
        title: input.title,
        description: input.description,
        startTime: selectedSlot.start,
        endTime: selectedSlot.end,
        durationMinutes,
        organizerId: input.organizerId,
        status: EventStatus.PENDING_CONFIRMATION,
        referenceType: input.referenceType,
        referenceId: input.referenceId,
        isAutoScheduled: true,
        autoScheduleRuleId: rule?.id,
        previousEventId: input.previousEventId,
        rescheduleCount: input.rescheduleCount ?? 0,
        lastRescheduledAt: input.rescheduleCount ? new Date() : undefined,
      });

      const savedEvent = await calendarRepo.save(event);

      const eventParticipants = participantIds.map((userId) => {
        const role =
          userId === input.organizerId
            ? ParticipantRole.ORGANIZER
            : requiredIds.includes(userId)
              ? ParticipantRole.REQUIRED
              : ParticipantRole.OPTIONAL;
        const isOrganizer = userId === input.organizerId;

        return participantRepo.create({
          eventId: savedEvent.id,
          userId,
          role,
          status: isOrganizer ? ParticipantStatus.ACCEPTED : ParticipantStatus.PENDING,
          respondedAt: isOrganizer ? new Date() : undefined,
          responseDeadline,
        });
      });

      const savedParticipants = await participantRepo.save(eventParticipants);

      const busySlots = participantIds.map((userId) =>
        availabilityRepo.create({
          userId,
          startTime: selectedSlot.start,
          endTime: selectedSlot.end,
          type: AvailabilityType.BUSY,
          isAutoGenerated: true,
          linkedEventId: savedEvent.id,
          note: 'Auto-scheduled event',
        }),
      );
      await availabilityRepo.save(busySlots);

      await this.updateStaffWorkload(
        manager,
        savedEvent.organizerId,
        durationMinutes,
        savedEvent.startTime,
      );

      this.logger.log(
        `Auto-scheduled event ${savedEvent.id} at ${selectedSlot.start.toISOString()}`,
      );

      return {
        manualRequired: false,
        selectedSlot: { start: selectedSlot.start, end: selectedSlot.end },
        event: savedEvent,
        participants: savedParticipants,
      };
    });
  }

  async handleRescheduleRequest(
    requestId: string,
    processorId?: string,
  ): Promise<RescheduleResult> {
    const request = await this.rescheduleRepository.findOne({ where: { id: requestId } });
    if (!request) {
      throw new BadRequestException('Reschedule request not found');
    }

    const event = await this.calendarRepository.findOne({ where: { id: request.eventId } });
    if (!event) {
      throw new BadRequestException('Calendar event not found');
    }

    if (
      ![EventStatus.SCHEDULED, EventStatus.PENDING_CONFIRMATION, EventStatus.RESCHEDULING].includes(
        event.status,
      )
    ) {
      throw new BadRequestException(`Event is ${event.status}, cannot reschedule`);
    }

    const rule = await this.resolveRule(event.type);
    const rescheduleLimit = Math.min(
      AUTO_RESCHEDULE_LIMIT,
      rule?.maxRescheduleCount ?? AUTO_RESCHEDULE_LIMIT,
    );
    const minNoticeHours = rule?.minRescheduleNoticeHours ?? DEFAULT_MIN_RESCHEDULE_NOTICE_HOURS;

    const rescheduleCutoff = new Date(event.startTime.getTime() - minNoticeHours * 60 * 60 * 1000);
    if (new Date() >= rescheduleCutoff) {
      await this.rescheduleRepository.update(request.id, {
        status: RescheduleRequestStatus.REJECTED,
        processedById: processorId,
        processedAt: new Date(),
        processNote: 'Too close to scheduled time to reschedule',
      });
      return { manualRequired: true, reason: 'Reschedule window closed' };
    }

    if (event.rescheduleCount >= rescheduleLimit) {
      await this.rescheduleRepository.update(request.id, {
        status: RescheduleRequestStatus.REJECTED,
        processedById: processorId,
        processedAt: new Date(),
        processNote: 'Reschedule limit reached',
      });
      return { manualRequired: true, reason: 'Reschedule limit reached' };
    }

    const participants = await this.participantRepository.find({
      where: { eventId: event.id },
    });
    const participantIds = participants.map((p) => p.userId);

    const durationMinutes = event.durationMinutes;

    let selectedSlot: { start: Date; end: Date } | null = null;

    if (request.proposedTimeSlots && request.proposedTimeSlots.length > 0) {
      const scored = await this.scoreProposedSlots(
        participantIds,
        durationMinutes,
        request.proposedTimeSlots,
        rule,
      );
      if (scored.length > 0) {
        selectedSlot = scored[0];
      }
    }

    if (!selectedSlot && request.useAutoSchedule) {
      const dateRange = {
        start: new Date(),
        end: this.addDays(new Date(), DEFAULT_RESCHEDULE_WINDOW_DAYS),
      };
      const autoResult = await this.autoScheduleEvent({
        eventType: event.type,
        title: event.title,
        organizerId: event.organizerId,
        participantIds,
        requiredParticipantIds: participants
          .filter((p) => p.role === ParticipantRole.REQUIRED)
          .map((p) => p.userId),
        dateRange,
        description: event.description || undefined,
        durationMinutes,
        referenceType: event.referenceType,
        referenceId: event.referenceId,
        autoScheduleRuleId: rule?.id,
        previousEventId: event.id,
        rescheduleCount: event.rescheduleCount + 1,
      });

      if (autoResult.manualRequired || !autoResult.event) {
        await this.rescheduleRepository.update(request.id, {
          status: RescheduleRequestStatus.REJECTED,
          processedById: processorId,
          processedAt: new Date(),
          processNote: autoResult.reason || 'Auto schedule failed',
        });
        return { manualRequired: true, reason: autoResult.reason };
      }

      await this.calendarRepository.update(event.id, {
        status: EventStatus.RESCHEDULING,
      });
      await this.availabilityRepository.delete({
        linkedEventId: event.id,
        isAutoGenerated: true,
      });

      await this.rescheduleRepository.update(request.id, {
        status: RescheduleRequestStatus.AUTO_RESOLVED,
        processedById: processorId,
        processedAt: new Date(),
        newEventId: autoResult.event.id,
        selectedNewStartTime: autoResult.event.startTime,
      });

      return {
        manualRequired: false,
        event: autoResult.event,
        participants: autoResult.participants,
      };
    }

    if (!selectedSlot) {
      await this.rescheduleRepository.update(request.id, {
        status: RescheduleRequestStatus.REJECTED,
        processedById: processorId,
        processedAt: new Date(),
        processNote: 'No valid slot proposed',
      });
      return { manualRequired: true, reason: 'No valid slot proposed' };
    }

    return this.dataSource.transaction(async (manager) => {
      await this.acquireSchedulingLocks(manager, participantIds);

      const conflict = await this.hasConflict(
        manager,
        participantIds,
        selectedSlot.start,
        selectedSlot.end,
      );
      if (conflict) {
        await this.rescheduleRepository.update(request.id, {
          status: RescheduleRequestStatus.REJECTED,
          processedById: processorId,
          processedAt: new Date(),
          processNote: 'Selected slot is no longer available',
        });
        return { manualRequired: true, reason: 'Slot is no longer available' };
      }

      const calendarRepo = manager.getRepository(CalendarEventEntity);
      const participantRepo = manager.getRepository(EventParticipantEntity);
      const availabilityRepo = manager.getRepository(UserAvailabilityEntity);

      await availabilityRepo.delete({ linkedEventId: event.id, isAutoGenerated: true });

      await calendarRepo.update(event.id, {
        status: EventStatus.RESCHEDULING,
        rescheduleCount: event.rescheduleCount + 1,
        lastRescheduledAt: new Date(),
      });

      const newEvent = calendarRepo.create({
        type: event.type,
        title: event.title,
        description: event.description,
        startTime: selectedSlot.start,
        endTime: selectedSlot.end,
        durationMinutes,
        organizerId: event.organizerId,
        status: EventStatus.PENDING_CONFIRMATION,
        referenceType: event.referenceType,
        referenceId: event.referenceId,
        previousEventId: event.id,
        rescheduleCount: event.rescheduleCount + 1,
        lastRescheduledAt: new Date(),
        isAutoScheduled: event.isAutoScheduled,
        autoScheduleRuleId: event.autoScheduleRuleId,
      });

      const savedEvent = await calendarRepo.save(newEvent);

      const newParticipants = participants.map((participant) =>
        participantRepo.create({
          eventId: savedEvent.id,
          userId: participant.userId,
          role: participant.role,
          status:
            participant.role === ParticipantRole.ORGANIZER
              ? ParticipantStatus.ACCEPTED
              : ParticipantStatus.PENDING,
          respondedAt: participant.role === ParticipantRole.ORGANIZER ? new Date() : undefined,
          responseDeadline: this.calculateResponseDeadline(
            savedEvent.startTime,
            rule?.minRescheduleNoticeHours,
          ),
        }),
      );

      const savedParticipants = await participantRepo.save(newParticipants);

      const busySlots = participantIds.map((userId) =>
        availabilityRepo.create({
          userId,
          startTime: selectedSlot.start,
          endTime: selectedSlot.end,
          type: AvailabilityType.BUSY,
          isAutoGenerated: true,
          linkedEventId: savedEvent.id,
          note: 'Rescheduled event',
        }),
      );
      await availabilityRepo.save(busySlots);

      await this.updateStaffWorkload(
        manager,
        savedEvent.organizerId,
        durationMinutes,
        savedEvent.startTime,
      );

      await this.rescheduleRepository.update(request.id, {
        status: RescheduleRequestStatus.APPROVED,
        processedById: processorId,
        processedAt: new Date(),
        newEventId: savedEvent.id,
        selectedNewStartTime: savedEvent.startTime,
      });

      return { manualRequired: false, event: savedEvent, participants: savedParticipants };
    });
  }

  async processManualRescheduleRequest(
    requestId: string,
    selectedStartTime: Date,
    processorId?: string,
    processNote?: string,
  ): Promise<RescheduleResult> {
    const request = await this.rescheduleRepository.findOne({ where: { id: requestId } });
    if (!request) {
      throw new BadRequestException('Reschedule request not found');
    }

    if (request.status !== RescheduleRequestStatus.PENDING) {
      throw new BadRequestException('Reschedule request already processed');
    }

    const event = await this.calendarRepository.findOne({ where: { id: request.eventId } });
    if (!event) {
      throw new BadRequestException('Calendar event not found');
    }

    if (
      ![EventStatus.SCHEDULED, EventStatus.PENDING_CONFIRMATION, EventStatus.RESCHEDULING].includes(
        event.status,
      )
    ) {
      throw new BadRequestException(`Event is ${event.status}, cannot reschedule`);
    }

    const rule = await this.resolveRule(event.type);
    const rescheduleLimit = Math.min(
      AUTO_RESCHEDULE_LIMIT,
      rule?.maxRescheduleCount ?? AUTO_RESCHEDULE_LIMIT,
    );
    const minNoticeHours = rule?.minRescheduleNoticeHours ?? DEFAULT_MIN_RESCHEDULE_NOTICE_HOURS;

    const rescheduleCutoff = new Date(event.startTime.getTime() - minNoticeHours * 60 * 60 * 1000);
    if (new Date() >= rescheduleCutoff) {
      await this.rescheduleRepository.update(request.id, {
        status: RescheduleRequestStatus.REJECTED,
        processedById: processorId,
        processedAt: new Date(),
        processNote: 'Too close to scheduled time to reschedule',
      });
      return { manualRequired: true, reason: 'Reschedule window closed' };
    }

    if (event.rescheduleCount >= rescheduleLimit) {
      await this.rescheduleRepository.update(request.id, {
        status: RescheduleRequestStatus.REJECTED,
        processedById: processorId,
        processedAt: new Date(),
        processNote: 'Reschedule limit reached',
      });
      return { manualRequired: true, reason: 'Reschedule limit reached' };
    }

    const start = new Date(selectedStartTime);
    if (Number.isNaN(start.getTime())) {
      throw new BadRequestException('Invalid selected start time');
    }

    const proposedSlots = (request.proposedTimeSlots || []).map((slot) => ({
      start: new Date(slot.start),
      end: new Date(slot.end),
    }));

    if (proposedSlots.length > 0) {
      const matched = proposedSlots.find((slot) => slot.start.getTime() === start.getTime());
      if (!matched) {
        throw new BadRequestException('Selected time is not in proposed slots');
      }

      const expectedEnd = new Date(start.getTime() + event.durationMinutes * 60 * 1000);
      if (Number.isNaN(matched.end.getTime()) || matched.end.getTime() < expectedEnd.getTime()) {
        throw new BadRequestException('Selected slot is shorter than event duration');
      }
    }

    const end = new Date(start.getTime() + event.durationMinutes * 60 * 1000);
    if (Number.isNaN(end.getTime()) || end <= start) {
      throw new BadRequestException('Invalid selected time slot');
    }

    const participants = await this.participantRepository.find({
      where: { eventId: event.id },
    });
    const participantIds = participants.map((p) => p.userId);

    return this.dataSource.transaction(async (manager) => {
      await this.acquireSchedulingLocks(manager, participantIds);

      const conflict = await this.hasConflict(manager, participantIds, start, end);
      if (conflict) {
        await this.rescheduleRepository.update(request.id, {
          status: RescheduleRequestStatus.REJECTED,
          processedById: processorId,
          processedAt: new Date(),
          processNote: 'Selected slot is no longer available',
        });
        return { manualRequired: true, reason: 'Slot is no longer available' };
      }

      const calendarRepo = manager.getRepository(CalendarEventEntity);
      const participantRepo = manager.getRepository(EventParticipantEntity);
      const availabilityRepo = manager.getRepository(UserAvailabilityEntity);

      await availabilityRepo.delete({ linkedEventId: event.id, isAutoGenerated: true });

      await calendarRepo.update(event.id, {
        status: EventStatus.RESCHEDULING,
        rescheduleCount: event.rescheduleCount + 1,
        lastRescheduledAt: new Date(),
      });

      const newEvent = calendarRepo.create({
        type: event.type,
        title: event.title,
        description: event.description,
        startTime: start,
        endTime: end,
        durationMinutes: event.durationMinutes,
        organizerId: event.organizerId,
        status: EventStatus.PENDING_CONFIRMATION,
        referenceType: event.referenceType,
        referenceId: event.referenceId,
        previousEventId: event.id,
        rescheduleCount: event.rescheduleCount + 1,
        lastRescheduledAt: new Date(),
        isAutoScheduled: event.isAutoScheduled,
        autoScheduleRuleId: event.autoScheduleRuleId,
      });

      const savedEvent = await calendarRepo.save(newEvent);

      const newParticipants = participants.map((participant) =>
        participantRepo.create({
          eventId: savedEvent.id,
          userId: participant.userId,
          role: participant.role,
          status:
            participant.role === ParticipantRole.ORGANIZER
              ? ParticipantStatus.ACCEPTED
              : ParticipantStatus.PENDING,
          respondedAt: participant.role === ParticipantRole.ORGANIZER ? new Date() : undefined,
          responseDeadline: this.calculateResponseDeadline(
            savedEvent.startTime,
            rule?.minRescheduleNoticeHours,
          ),
        }),
      );

      const savedParticipants = await participantRepo.save(newParticipants);

      const busySlots = participantIds.map((userId) =>
        availabilityRepo.create({
          userId,
          startTime: start,
          endTime: end,
          type: AvailabilityType.BUSY,
          isAutoGenerated: true,
          linkedEventId: savedEvent.id,
          note: 'Rescheduled event',
        }),
      );
      await availabilityRepo.save(busySlots);

      await this.updateStaffWorkload(
        manager,
        savedEvent.organizerId,
        event.durationMinutes,
        savedEvent.startTime,
      );

      await this.rescheduleRepository.update(request.id, {
        status: RescheduleRequestStatus.APPROVED,
        processedById: processorId,
        processedAt: new Date(),
        processNote,
        newEventId: savedEvent.id,
        selectedNewStartTime: savedEvent.startTime,
      });

      return { manualRequired: false, event: savedEvent, participants: savedParticipants };
    });
  }

  async processEventInvitations(
    participantId: string,
    response: 'accept' | 'decline' | 'tentative',
    responseNote?: string,
  ): Promise<{
    event: CalendarEventEntity;
    participant: EventParticipantEntity;
    manualRequired: boolean;
    reason?: string;
  }> {
    const participant = await this.participantRepository.findOne({
      where: { id: participantId },
    });
    if (!participant) {
      throw new BadRequestException('Participant not found');
    }

    const event = await this.calendarRepository.findOne({ where: { id: participant.eventId } });
    if (!event) {
      throw new BadRequestException('Calendar event not found');
    }

    if ([EventStatus.CANCELLED, EventStatus.COMPLETED].includes(event.status)) {
      throw new BadRequestException(`Event is ${event.status}, cannot respond`);
    }

    participant.status =
      response === 'accept'
        ? ParticipantStatus.ACCEPTED
        : response === 'decline'
          ? ParticipantStatus.DECLINED
          : ParticipantStatus.TENTATIVE;
    participant.respondedAt = new Date();
    participant.responseNote = responseNote;
    await this.participantRepository.save(participant);

    if (participant.role === ParticipantRole.REQUIRED && response === 'decline') {
      const rule = await this.resolveRule(event.type);
      const rescheduleLimit = Math.min(
        AUTO_RESCHEDULE_LIMIT,
        rule?.maxRescheduleCount ?? AUTO_RESCHEDULE_LIMIT,
      );

      if (event.rescheduleCount >= rescheduleLimit) {
        await this.calendarRepository.update(event.id, {
          status: EventStatus.RESCHEDULING,
          metadata: {
            ...(event.metadata || {}),
            manualNegotiationRequired: true,
            rejectionLoop: true,
          },
        });
        return {
          event,
          participant,
          manualRequired: true,
          reason: 'Auto reschedule limit reached',
        };
      }

      await this.calendarRepository.update(event.id, {
        status: EventStatus.RESCHEDULING,
        rescheduleCount: event.rescheduleCount + 1,
        lastRescheduledAt: new Date(),
      });

      const rescheduleRequest = this.rescheduleRepository.create({
        eventId: event.id,
        requesterId: participant.userId,
        reason: responseNote || 'Auto reschedule triggered by decline',
        useAutoSchedule: true,
        status: RescheduleRequestStatus.PENDING,
      });
      const savedRequest = await this.rescheduleRepository.save(rescheduleRequest);

      const rescheduleResult = await this.handleRescheduleRequest(
        savedRequest.id,
        event.organizerId,
      );
      return {
        event,
        participant,
        manualRequired: rescheduleResult.manualRequired,
        reason: rescheduleResult.reason,
      };
    }

    const requiredParticipants = await this.participantRepository.find({
      where: {
        eventId: event.id,
        role: ParticipantRole.REQUIRED,
      },
    });

    const allRequiredAccepted = requiredParticipants.every(
      (p) => p.status === ParticipantStatus.ACCEPTED,
    );

    if (allRequiredAccepted) {
      await this.calendarRepository.update(event.id, {
        status: EventStatus.SCHEDULED,
      });
    }

    return {
      event,
      participant,
      manualRequired: false,
    };
  }

  private async resolveRule(eventType: EventType, ruleId?: string) {
    if (ruleId) {
      return this.ruleRepository.findOne({ where: { id: ruleId, isActive: true } });
    }

    const defaultRule = await this.ruleRepository.findOne({
      where: { eventType, isActive: true, isDefault: true },
    });
    if (defaultRule) {
      return defaultRule;
    }

    return this.ruleRepository.findOne({ where: { eventType, isActive: true } });
  }

  private widenRange(range: { start: Date; end: Date }) {
    const start = new Date(range.start);
    const end = new Date(range.end);
    return {
      start: this.addDays(start, 1),
      end: this.addDays(end, 3),
    };
  }

  private async scoreProposedSlots(
    participantIds: string[],
    durationMinutes: number,
    proposedSlots: Array<{ start: Date; end: Date }>,
    rule?: AutoScheduleRuleEntity | null,
  ): Promise<Array<{ start: Date; end: Date }>> {
    const scored: Array<{ start: Date; end: Date; score: number }> = [];

    for (const slot of proposedSlots) {
      const range = { start: new Date(slot.start), end: new Date(slot.end) };
      if (
        Number.isNaN(range.start.getTime()) ||
        Number.isNaN(range.end.getTime()) ||
        range.start >= range.end
      ) {
        continue;
      }
      const slotInput: FindAvailableSlotsInput = {
        userIds: participantIds,
        durationMinutes,
        dateRange: range,
        constraints: rule
          ? {
              workingHoursStart: rule.workingHoursStart,
              workingHoursEnd: rule.workingHoursEnd,
              workingDays: rule.workingDays,
              bufferMinutes: rule.bufferMinutes,
              lunchStart: rule.lunchStartTime,
              lunchEnd: rule.lunchEndTime,
              avoidLunchHours: rule.avoidLunchHours,
              maxEventsPerStaffPerDay: rule.maxEventsPerStaffPerDay,
            }
          : undefined,
        maxSlots: 1,
        stepMinutes: durationMinutes,
      };

      const result = await this.calendarService.findAvailableSlots(slotInput);
      if (result.slots.length === 0) {
        continue;
      }

      const candidate = result.slots[0];
      if (candidate.start.getTime() !== range.start.getTime()) {
        continue;
      }

      scored.push({ start: candidate.start, end: candidate.end, score: candidate.score });
    }

    scored.sort((a, b) => b.score - a.score);
    return scored.map((item) => ({ start: item.start, end: item.end }));
  }

  private async acquireSchedulingLocks(manager: EntityManager, userIds: string[]) {
    const uniqueSorted = Array.from(new Set(userIds)).sort();
    for (const userId of uniqueSorted) {
      await manager.query('SELECT pg_advisory_xact_lock(hashtext($1))', [userId]);
    }
  }

  private async pickFirstAvailableSlot(
    manager: EntityManager,
    slots: Array<{ start: Date; end: Date }>,
    participantIds: string[],
  ) {
    for (const slot of slots) {
      const conflict = await this.hasConflict(manager, participantIds, slot.start, slot.end);
      if (!conflict) {
        return { start: slot.start, end: slot.end };
      }
    }
    return null;
  }

  private async hasConflict(
    manager: EntityManager,
    participantIds: string[],
    start: Date,
    end: Date,
  ): Promise<boolean> {
    const eventRepo = manager.getRepository(CalendarEventEntity);
    const participantRepo = manager.getRepository(EventParticipantEntity);
    const availabilityRepo = manager.getRepository(UserAvailabilityEntity);

    const overlappingEvents = await eventRepo.find({
      where: {
        organizerId: In(participantIds),
        startTime: LessThan(end),
        endTime: MoreThan(start),
        status: In(ACTIVE_EVENT_STATUSES),
      },
    });

    if (overlappingEvents.length > 0) {
      return true;
    }

    const participantEvents = await participantRepo
      .createQueryBuilder('participant')
      .innerJoinAndSelect('participant.event', 'event')
      .where('participant.userId IN (:...userIds)', { userIds: participantIds })
      .andWhere('event.startTime < :end AND event.endTime > :start', { start, end })
      .andWhere('event.status IN (:...statuses)', { statuses: ACTIVE_EVENT_STATUSES })
      .getMany();

    if (participantEvents.length > 0) {
      return true;
    }

    const busy = await availabilityRepo.find({
      where: {
        userId: In(participantIds),
        type: In(BUSY_AVAILABILITY_TYPES),
        startTime: LessThan(end),
        endTime: MoreThan(start),
      },
    });

    return busy.length > 0;
  }

  private calculateResponseDeadline(startTime: Date, minNoticeHours?: number) {
    const fallbackHours = minNoticeHours ?? DEFAULT_RESPONSE_DEADLINE_HOURS;
    const deadline = new Date(startTime.getTime() - fallbackHours * 60 * 60 * 1000);
    return deadline > new Date() ? deadline : new Date();
  }

  private async updateStaffWorkload(
    manager: EntityManager,
    organizerId: string,
    durationMinutes: number,
    eventStart: Date,
  ) {
    const userRepo = manager.getRepository(UserEntity);
    const user = await userRepo.findOne({
      where: { id: organizerId },
      select: ['id', 'role'],
    });
    if (!user || user.role !== UserRole.STAFF) {
      return;
    }

    const dateKey = new Date(eventStart.getFullYear(), eventStart.getMonth(), eventStart.getDate());

    const workloadRepo = manager.getRepository(StaffWorkloadEntity);
    const existing = await workloadRepo.findOne({
      where: { staffId: organizerId, date: dateKey as any },
    });

    if (existing) {
      const scheduledMinutes = existing.scheduledMinutes + durationMinutes;
      const utilizationRate = (scheduledMinutes / existing.dailyCapacityMinutes) * 100;
      await workloadRepo.update(existing.id, {
        scheduledMinutes,
        totalEventsScheduled: existing.totalEventsScheduled + 1,
        utilizationRate: Math.round(utilizationRate * 100) / 100,
        isOverloaded: utilizationRate >= 90,
        canAcceptNewEvent: utilizationRate < 80,
      });
    } else {
      const utilizationRate = (durationMinutes / 480) * 100;
      await workloadRepo.save(
        workloadRepo.create({
          staffId: organizerId,
          date: dateKey as any,
          totalEventsScheduled: 1,
          scheduledMinutes: durationMinutes,
          dailyCapacityMinutes: 480,
          utilizationRate: Math.round(utilizationRate * 100) / 100,
          isOverloaded: utilizationRate >= 90,
          canAcceptNewEvent: utilizationRate < 80,
        }),
      );
    }
  }

  private addDays(date: Date, days: number) {
    const next = new Date(date);
    next.setDate(next.getDate() + days);
    return next;
  }
}

import {
  BadRequestException,
  Injectable,
  Logger,
  Optional,
  NotFoundException,
} from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { InjectRepository } from '@nestjs/typeorm';
import { DataSource, In, LessThan, MoreThan, Repository } from 'typeorm';

import {
  CalendarEventEntity,
  EventStatus,
  EventRescheduleRequestEntity,
  RescheduleRequestStatus,
  UserEntity,
} from 'src/database/entities';
import { EventParticipantEntity } from 'src/database/entities/event-participant.entity';
import {
  AvailabilityType,
  UserAvailabilityEntity,
} from 'src/database/entities/user-availability.entity';
import { CreateAvailabilityDto, CreateRecurringAvailabilityDto } from './dto/availability.dto';
import { AutoScheduleService } from './auto-schedule.service';
import { buildUtcDateFromLocalTime, DEFAULT_SCHEDULING_CONSTRAINTS } from './calendar.utils';

const ACTIVE_EVENT_STATUSES = [
  EventStatus.SCHEDULED,
  EventStatus.PENDING_CONFIRMATION,
  EventStatus.IN_PROGRESS,
  EventStatus.RESCHEDULING,
];

const BLOCKING_TYPES = [
  AvailabilityType.BUSY,
  AvailabilityType.OUT_OF_OFFICE,
  AvailabilityType.DO_NOT_DISTURB,
];

export interface SetAvailabilityInput {
  userId: string;
  slots?: CreateAvailabilityDto[];
  recurring?: CreateRecurringAvailabilityDto;
  allowConflicts?: boolean;
  timeZone?: string;
  isAutoGenerated?: boolean;
  linkedLeaveRequestId?: string;
}

export interface SetAvailabilityResult {
  entries: UserAvailabilityEntity[];
  conflictingEvents: CalendarEventEntity[];
  rescheduleRequests: Array<{ eventId: string; requestId: string; status: string }>;
}

@Injectable()
export class AvailabilityService {
  private readonly logger = new Logger(AvailabilityService.name);

  constructor(
    @InjectRepository(UserAvailabilityEntity)
    private readonly availabilityRepository: Repository<UserAvailabilityEntity>,
    @InjectRepository(CalendarEventEntity)
    private readonly calendarRepository: Repository<CalendarEventEntity>,
    @InjectRepository(EventParticipantEntity)
    private readonly participantRepository: Repository<EventParticipantEntity>,
    @InjectRepository(EventRescheduleRequestEntity)
    private readonly rescheduleRepository: Repository<EventRescheduleRequestEntity>,
    @InjectRepository(UserEntity)
    private readonly userRepository: Repository<UserEntity>,
    private readonly dataSource: DataSource,
    @Optional() private readonly autoScheduleService?: AutoScheduleService,
    @Optional() private readonly eventEmitter?: EventEmitter2,
  ) {}

  async setUserAvailability(input: SetAvailabilityInput): Promise<SetAvailabilityResult> {
    if (!input.slots?.length && !input.recurring) {
      throw new BadRequestException('slots or recurring availability is required');
    }

    const user = await this.userRepository.findOne({
      where: { id: input.userId },
      select: ['id', 'timeZone'],
    });
    const userTimeZone = input.timeZone || user?.timeZone || 'UTC';

    if (input.timeZone && user && user.timeZone !== input.timeZone) {
      await this.userRepository.update({ id: input.userId }, { timeZone: input.timeZone });
    }

    const createdEntries: UserAvailabilityEntity[] = [];
    const conflictRanges: Array<{ start: Date; end: Date }> = [];
    const autoGenerated = Boolean(input.isAutoGenerated);

    if (input.slots?.length) {
      const workingStartMinutes = this.parseTimeToMinutes(
        DEFAULT_SCHEDULING_CONSTRAINTS.workingHoursStart,
      );
      const workingEndMinutes = this.parseTimeToMinutes(
        DEFAULT_SCHEDULING_CONSTRAINTS.workingHoursEnd,
      );

      const normalizedSlots = input.slots.map((slot) => {
        const start = this.parseDateTime(slot.startTime, userTimeZone);
        const end = this.parseDateTime(slot.endTime, userTimeZone);
        if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime()) || start >= end) {
          throw new BadRequestException('Invalid availability time slot');
        }
        const now = new Date();
        if (start < now) {
          throw new BadRequestException('Cannot add availability in the past');
        }
        const startDateKey = this.getLocalDateKey(start, userTimeZone);
        const endDateKey = this.getLocalDateKey(end, userTimeZone);
        if (startDateKey !== endDateKey) {
          throw new BadRequestException('Availability must be within a single working day');
        }
        const startMinutes = this.getLocalTimeMinutes(start, userTimeZone);
        const endMinutes = this.getLocalTimeMinutes(end, userTimeZone);
        if (startMinutes < workingStartMinutes || endMinutes > workingEndMinutes) {
          throw new BadRequestException('Availability must be within working hours (08:00-18:00)');
        }
        if (
          slot.type === AvailabilityType.OUT_OF_OFFICE &&
          end.getTime() - start.getTime() > 24 * 60 * 60 * 1000
        ) {
          throw new BadRequestException('Out of office longer than 1 day requires admin approval');
        }
        return { ...slot, startTime: start, endTime: end };
      });

      this.assertNoOverlaps(
        normalizedSlots.map((slot) => ({ start: slot.startTime, end: slot.endTime })),
      );

      for (const slot of normalizedSlots) {
        await this.assertNoExistingOverlap(input.userId, slot.startTime, slot.endTime);
        const entry = this.availabilityRepository.create({
          userId: input.userId,
          startTime: slot.startTime,
          endTime: slot.endTime,
          type: slot.type,
          note: slot.note,
          isRecurring: false,
          isAutoGenerated: autoGenerated,
          linkedLeaveRequestId: input.linkedLeaveRequestId,
        });
        createdEntries.push(entry);

        if (BLOCKING_TYPES.includes(slot.type)) {
          conflictRanges.push({ start: slot.startTime, end: slot.endTime });
        }
      }
    }

    if (input.recurring) {
      if (!input.recurring.slots?.length) {
        throw new BadRequestException('Recurring slots are required');
      }

      const recurringStart = input.recurring.startDate
        ? this.parseLocalDateOnly(input.recurring.startDate, userTimeZone)
        : null;
      const recurringEnd = input.recurring.endDate
        ? this.parseLocalDateOnly(input.recurring.endDate, userTimeZone)
        : null;
      if (
        (recurringStart && Number.isNaN(recurringStart.getTime())) ||
        (recurringEnd && Number.isNaN(recurringEnd.getTime()))
      ) {
        throw new BadRequestException('Invalid recurring date range');
      }
      if (recurringStart && recurringEnd && recurringStart >= recurringEnd) {
        throw new BadRequestException('Recurring startDate must be before endDate');
      }

      this.assertNoRecurringOverlaps(input.recurring.slots);

      const workingStartMinutes = this.parseTimeToMinutes(
        DEFAULT_SCHEDULING_CONSTRAINTS.workingHoursStart,
      );
      const workingEndMinutes = this.parseTimeToMinutes(
        DEFAULT_SCHEDULING_CONSTRAINTS.workingHoursEnd,
      );

      const dayOfWeekValues = input.recurring.slots.map((slot) => slot.dayOfWeek);
      const existingRecurring = await this.availabilityRepository.find({
        where: {
          userId: input.userId,
          isRecurring: true,
          dayOfWeek: In(dayOfWeekValues),
        },
      });

      for (const slot of input.recurring.slots) {
        this.assertValidDayOfWeek(slot.dayOfWeek);
        const startMinutes = this.parseTimeToMinutes(slot.startTime);
        const endMinutes = this.parseTimeToMinutes(slot.endTime);
        if (startMinutes >= endMinutes) {
          throw new BadRequestException('Recurring slot startTime must be before endTime');
        }
        if (startMinutes < workingStartMinutes || endMinutes > workingEndMinutes) {
          throw new BadRequestException('Recurring availability must be within working hours');
        }

        for (const existing of existingRecurring.filter(
          (entry) => entry.dayOfWeek === slot.dayOfWeek,
        )) {
          const existingStart = this.parseTimeToMinutes(existing.recurringStartTime || '00:00');
          const existingEnd = this.parseTimeToMinutes(existing.recurringEndTime || '00:00');
          if (this.overlaps(startMinutes, endMinutes, existingStart, existingEnd)) {
            if (
              this.dateRangesOverlap(
                input.recurring.startDate ? new Date(input.recurring.startDate) : null,
                input.recurring.endDate ? new Date(input.recurring.endDate) : null,
                existing.recurringStartDate ? new Date(existing.recurringStartDate) : null,
                existing.recurringEndDate ? new Date(existing.recurringEndDate) : null,
              )
            ) {
              throw new BadRequestException('Recurring availability overlaps existing slot');
            }
          }
        }

        const entryData = {
          userId: input.userId,
          type: input.recurring.type,
          isRecurring: true,
          dayOfWeek: slot.dayOfWeek,
          recurringStartTime: slot.startTime,
          recurringEndTime: slot.endTime,
          recurringStartDate: recurringStart ?? undefined,
          recurringEndDate: recurringEnd ?? undefined,
          note: input.recurring.note,
          isAutoGenerated: autoGenerated,
          linkedLeaveRequestId: input.linkedLeaveRequestId,
        };
        const entry = this.availabilityRepository.create(entryData);
        createdEntries.push(entry);
      }

      if (BLOCKING_TYPES.includes(input.recurring.type)) {
        const { start, end } = this.resolveRecurringRange(input.recurring);
        const expanded = this.expandRecurringSlots(input.recurring.slots, start, end);
        conflictRanges.push(...expanded);
      }
    }

    const conflictingEvents = await this.findConflictingEvents(input.userId, conflictRanges, true);

    if (conflictingEvents.length > 0 && !input.allowConflicts) {
      throw new BadRequestException({
        message: 'Availability conflicts with existing events. Confirm to reschedule them.',
        conflicts: conflictingEvents.map((event) => ({
          eventId: event.id,
          title: event.title,
          startTime: event.startTime,
          endTime: event.endTime,
          status: event.status,
        })),
      });
    }

    const savedEntries = await this.availabilityRepository.save(createdEntries);
    const rescheduleRequests = await this.triggerRescheduleForConflicts(
      input.userId,
      conflictingEvents,
      Boolean(input.allowConflicts),
    );

    if (conflictingEvents.length > 0) {
      this.logger.warn(`Availability update conflicts with ${conflictingEvents.length} event(s)`);
    }

    this.eventEmitter?.emit('calendar.availabilityUpdated', {
      userId: input.userId,
      entries: savedEntries.map((entry) => entry.id),
      conflictEventIds: conflictingEvents.map((event) => event.id),
    });

    return { entries: savedEntries, conflictingEvents, rescheduleRequests };
  }

  async deleteUserAvailability(input: {
    userId: string;
    availabilityId: string;
  }): Promise<UserAvailabilityEntity> {
    const entry = await this.availabilityRepository.findOne({
      where: { id: input.availabilityId, userId: input.userId },
    });
    if (!entry) {
      throw new NotFoundException('Availability slot not found');
    }
    if (entry.isAutoGenerated) {
      throw new BadRequestException('Cannot delete auto-generated availability');
    }
    if (entry.isRecurring) {
      throw new BadRequestException(
        'Recurring availability must be managed from schedule settings',
      );
    }
    const now = new Date();
    if (entry.startTime <= now) {
      throw new BadRequestException('Only future availability can be deleted');
    }

    await this.availabilityRepository.delete({ id: entry.id, userId: input.userId });
    this.eventEmitter?.emit('calendar.availabilityDeleted', {
      userId: input.userId,
      availabilityId: entry.id,
    });

    return entry;
  }

  async syncCalendarEvents(input: { start: Date; end: Date; userIds?: string[] }): Promise<{
    deleted: number;
    created: number;
    eventsSynced: number;
  }> {
    const rangeStart = new Date(input.start);
    const rangeEnd = new Date(input.end);
    if (
      Number.isNaN(rangeStart.getTime()) ||
      Number.isNaN(rangeEnd.getTime()) ||
      rangeStart >= rangeEnd
    ) {
      throw new BadRequestException('Invalid sync range');
    }

    return this.dataSource.transaction(async (manager) => {
      const availabilityRepo = manager.getRepository(UserAvailabilityEntity);
      const calendarRepo = manager.getRepository(CalendarEventEntity);
      const participantRepo = manager.getRepository(EventParticipantEntity);

      const events = await calendarRepo.find({
        where: {
          startTime: LessThan(rangeEnd),
          endTime: MoreThan(rangeStart),
          status: In(ACTIVE_EVENT_STATUSES),
        },
      });

      let filteredEvents = events;
      if (input.userIds?.length) {
        const participantEvents = await participantRepo.find({
          where: { userId: In(input.userIds) },
        });
        const participantEventIds = new Set(participantEvents.map((p) => p.eventId));
        filteredEvents = events.filter(
          (event) =>
            input.userIds!.includes(event.organizerId) || participantEventIds.has(event.id),
        );
      }

      const deleteQuery = availabilityRepo
        .createQueryBuilder()
        .delete()
        .where('isAutoGenerated = :auto', { auto: true })
        .andWhere('linkedEventId IS NOT NULL')
        .andWhere('startTime < :rangeEnd AND endTime > :rangeStart', {
          rangeStart,
          rangeEnd,
        });

      if (input.userIds?.length) {
        deleteQuery.andWhere('userId IN (:...userIds)', { userIds: input.userIds });
      }

      const deleteResult = await deleteQuery.execute();

      if (filteredEvents.length === 0) {
        return { deleted: deleteResult.affected || 0, created: 0, eventsSynced: 0 };
      }

      const eventIds = filteredEvents.map((event) => event.id);
      const participants = await participantRepo.find({
        where: { eventId: In(eventIds) },
      });
      const participantsByEvent = new Map<string, Set<string>>();
      for (const participant of participants) {
        const set = participantsByEvent.get(participant.eventId) ?? new Set<string>();
        set.add(participant.userId);
        participantsByEvent.set(participant.eventId, set);
      }

      const entries: UserAvailabilityEntity[] = [];
      for (const event of filteredEvents) {
        const userIds = new Set<string>([event.organizerId]);
        const participantIds = participantsByEvent.get(event.id);
        if (participantIds) {
          participantIds.forEach((id) => userIds.add(id));
        }

        for (const userId of userIds) {
          if (input.userIds?.length && !input.userIds.includes(userId)) {
            continue;
          }
          entries.push(
            availabilityRepo.create({
              userId,
              startTime: event.startTime,
              endTime: event.endTime,
              type: AvailabilityType.BUSY,
              isAutoGenerated: true,
              linkedEventId: event.id,
              note: 'Synced from calendar event',
            }),
          );
        }
      }

      const saved = await availabilityRepo.save(entries);

      return {
        deleted: deleteResult.affected || 0,
        created: saved.length,
        eventsSynced: filteredEvents.length,
      };
    });
  }

  private async assertNoExistingOverlap(userId: string, start: Date, end: Date): Promise<void> {
    const overlaps = await this.availabilityRepository.find({
      where: {
        userId,
        isAutoGenerated: false,
        startTime: LessThan(end),
        endTime: MoreThan(start),
      },
    });
    if (overlaps.length > 0) {
      throw new BadRequestException('Availability overlaps existing slots');
    }
  }

  private async findConflictingEvents(
    userId: string,
    ranges: Array<{ start: Date; end: Date }>,
    onlyFuture: boolean,
  ): Promise<CalendarEventEntity[]> {
    if (ranges.length === 0) {
      return [];
    }

    const conflicts = new Map<string, CalendarEventEntity>();
    const now = new Date();

    for (const range of ranges) {
      const organizerEvents = await this.calendarRepository.find({
        where: {
          organizerId: userId,
          startTime: LessThan(range.end),
          endTime: MoreThan(range.start),
          status: In(ACTIVE_EVENT_STATUSES),
        },
      });
      organizerEvents.forEach((event) => {
        if (!onlyFuture || event.endTime > now) {
          conflicts.set(event.id, event);
        }
      });

      const participantEvents = await this.participantRepository
        .createQueryBuilder('participant')
        .innerJoinAndSelect('participant.event', 'event')
        .where('participant.userId = :userId', { userId })
        .andWhere('event.startTime < :rangeEnd AND event.endTime > :rangeStart', {
          rangeStart: range.start,
          rangeEnd: range.end,
        })
        .andWhere('event.status IN (:...statuses)', { statuses: ACTIVE_EVENT_STATUSES })
        .getMany();

      for (const participant of participantEvents) {
        if (participant.event && (!onlyFuture || participant.event.endTime > now)) {
          conflicts.set(participant.event.id, participant.event);
        }
      }
    }

    return Array.from(conflicts.values());
  }

  private async triggerRescheduleForConflicts(
    userId: string,
    events: CalendarEventEntity[],
    allowConflicts: boolean,
  ): Promise<Array<{ eventId: string; requestId: string; status: string }>> {
    if (!allowConflicts || events.length === 0 || !this.autoScheduleService) {
      return [];
    }

    const pendingRequests = await this.rescheduleRepository.find({
      where: {
        eventId: In(events.map((event) => event.id)),
        status: RescheduleRequestStatus.PENDING,
      },
    });
    const pendingEventIds = new Set(pendingRequests.map((request) => request.eventId));

    const createdRequests: EventRescheduleRequestEntity[] = [];
    for (const event of events) {
      if (pendingEventIds.has(event.id)) {
        continue;
      }
      createdRequests.push(
        this.rescheduleRepository.create({
          eventId: event.id,
          requesterId: userId,
          reason: 'Availability update conflict',
          useAutoSchedule: true,
          status: RescheduleRequestStatus.PENDING,
        }),
      );
    }

    if (createdRequests.length === 0) {
      return [];
    }

    const saved = await this.rescheduleRepository.save(createdRequests);
    const results: Array<{ eventId: string; requestId: string; status: string }> = [];

    for (const request of saved) {
      const result = await this.autoScheduleService.handleRescheduleRequest(request.id, userId);
      results.push({
        eventId: request.eventId,
        requestId: request.id,
        status: result.manualRequired ? 'MANUAL_REQUIRED' : 'RESCHEDULED',
      });
    }

    return results;
  }

  private assertNoOverlaps(ranges: Array<{ start: Date; end: Date }>) {
    const sorted = [...ranges].sort((a, b) => a.start.getTime() - b.start.getTime());
    for (let i = 1; i < sorted.length; i += 1) {
      if (sorted[i].start < sorted[i - 1].end) {
        throw new BadRequestException('Availability slots overlap');
      }
    }
  }

  private overlaps(startA: number, endA: number, startB: number, endB: number): boolean {
    return startA < endB && endA > startB;
  }

  private parseTimeToMinutes(time: string): number {
    const [hour, minute, second] = time.split(':').map((value) => Number(value));
    const safeHour = Number.isFinite(hour) ? hour : 0;
    const safeMinute = Number.isFinite(minute) ? minute : 0;
    const safeSecond = Number.isFinite(second) ? second : 0;
    return safeHour * 60 + safeMinute + Math.floor(safeSecond / 60);
  }

  private getLocalDateKey(date: Date, timeZone: string): string {
    const formatter = new Intl.DateTimeFormat('en-CA', {
      timeZone,
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    });
    const parts = formatter.formatToParts(date);
    const year = parts.find((part) => part.type === 'year')?.value ?? '0000';
    const month = parts.find((part) => part.type === 'month')?.value ?? '00';
    const day = parts.find((part) => part.type === 'day')?.value ?? '00';
    return `${year}-${month}-${day}`;
  }

  private getLocalTimeMinutes(date: Date, timeZone: string): number {
    const formatter = new Intl.DateTimeFormat('en-US', {
      timeZone,
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: false,
    });
    const parts = formatter.formatToParts(date);
    const hour = Number(parts.find((part) => part.type === 'hour')?.value ?? '0');
    const minute = Number(parts.find((part) => part.type === 'minute')?.value ?? '0');
    const second = Number(parts.find((part) => part.type === 'second')?.value ?? '0');
    return hour * 60 + minute + second / 60;
  }

  private assertValidDayOfWeek(dayOfWeek: number) {
    if (!Number.isInteger(dayOfWeek) || dayOfWeek < 0 || dayOfWeek > 6) {
      throw new BadRequestException('dayOfWeek must be between 0 and 6');
    }
  }

  private dateRangesOverlap(
    startA: Date | null,
    endA: Date | null,
    startB: Date | null,
    endB: Date | null,
  ): boolean {
    const effectiveStartA = startA ?? new Date(0);
    const effectiveStartB = startB ?? new Date(0);
    const effectiveEndA = endA ?? new Date(8640000000000000);
    const effectiveEndB = endB ?? new Date(8640000000000000);
    return effectiveStartA <= effectiveEndB && effectiveStartB <= effectiveEndA;
  }

  private resolveRecurringRange(input: CreateRecurringAvailabilityDto): { start: Date; end: Date } {
    const start = input.startDate ? new Date(input.startDate) : new Date();
    const end = input.endDate ? new Date(input.endDate) : this.addDays(start, 30);
    if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime()) || start >= end) {
      throw new BadRequestException('Invalid recurring date range');
    }
    return { start, end };
  }

  private expandRecurringSlots(
    slots: CreateRecurringAvailabilityDto['slots'],
    rangeStart: Date,
    rangeEnd: Date,
  ): Array<{ start: Date; end: Date }> {
    const ranges: Array<{ start: Date; end: Date }> = [];
    const cursor = new Date(rangeStart);
    cursor.setHours(0, 0, 0, 0);
    const end = new Date(rangeEnd);
    end.setHours(23, 59, 59, 999);

    for (let day = new Date(cursor); day <= end; day = this.addDays(day, 1)) {
      for (const slot of slots) {
        if (day.getDay() !== slot.dayOfWeek) {
          continue;
        }
        const start = this.buildDateTime(day, slot.startTime);
        const endTime = this.buildDateTime(day, slot.endTime);
        if (start < rangeEnd && endTime > rangeStart) {
          ranges.push({ start, end: endTime });
        }
      }
    }
    return ranges;
  }

  private buildDateTime(base: Date, time: string): Date {
    const [hour, minute, second] = time.split(':').map((value) => Number(value));
    const result = new Date(base);
    result.setHours(
      Number.isFinite(hour) ? hour : 0,
      Number.isFinite(minute) ? minute : 0,
      Number.isFinite(second) ? second : 0,
      0,
    );
    return result;
  }

  private addDays(date: Date, days: number): Date {
    const next = new Date(date);
    next.setDate(next.getDate() + days);
    return next;
  }

  private assertNoRecurringOverlaps(slots: CreateRecurringAvailabilityDto['slots']) {
    const grouped = new Map<number, Array<{ start: number; end: number }>>();

    for (const slot of slots) {
      this.assertValidDayOfWeek(slot.dayOfWeek);
      const startMinutes = this.parseTimeToMinutes(slot.startTime);
      const endMinutes = this.parseTimeToMinutes(slot.endTime);
      if (startMinutes >= endMinutes) {
        throw new BadRequestException('Recurring slot startTime must be before endTime');
      }
      const list = grouped.get(slot.dayOfWeek) ?? [];
      list.push({ start: startMinutes, end: endMinutes });
      grouped.set(slot.dayOfWeek, list);
    }

    for (const ranges of grouped.values()) {
      const sorted = ranges.sort((a, b) => a.start - b.start);
      for (let i = 1; i < sorted.length; i += 1) {
        if (sorted[i].start < sorted[i - 1].end) {
          throw new BadRequestException('Recurring availability slots overlap');
        }
      }
    }
  }

  private parseDateTime(value: string, timeZone: string): Date {
    if (!value) {
      return new Date(NaN);
    }
    const hasOffset = /[zZ]|[+-]\d{2}:?\d{2}$/.test(value);
    if (hasOffset) {
      return new Date(value);
    }

    const [datePart, timePartRaw] = value.split('T');
    if (!datePart || !timePartRaw) {
      return new Date(value);
    }
    const [year, month, day] = datePart.split('-').map((part) => Number(part));
    if (!Number.isFinite(year) || !Number.isFinite(month) || !Number.isFinite(day)) {
      return new Date(value);
    }
    const timePart = timePartRaw.length === 5 ? `${timePartRaw}:00` : timePartRaw;
    const baseDate = new Date(Date.UTC(year, month - 1, day, 0, 0, 0));
    return buildUtcDateFromLocalTime(baseDate, timePart, timeZone);
  }

  private parseLocalDateOnly(value: string, timeZone: string): Date {
    if (!value) {
      return new Date(NaN);
    }
    const [year, month, day] = value.split('-').map((part) => Number(part));
    if (!Number.isFinite(year) || !Number.isFinite(month) || !Number.isFinite(day)) {
      return new Date(value);
    }
    const baseDate = new Date(Date.UTC(year, month - 1, day, 0, 0, 0));
    return buildUtcDateFromLocalTime(baseDate, '00:00:00', timeZone);
  }
}

import {
  BadRequestException,
  Controller,
  ForbiddenException,
  Delete,
  Get,
  HttpCode,
  HttpStatus,
  NotFoundException,
  Param,
  ParseUUIDPipe,
  Patch,
  Post,
  Query,
  Body,
  UseGuards,
  Headers,
} from '@nestjs/common';
import {
  ApiBearerAuth,
  ApiOperation,
  ApiParam,
  ApiQuery,
  ApiResponse,
  ApiTags,
} from '@nestjs/swagger';
import { InjectRepository } from '@nestjs/typeorm';
import { Brackets, In, LessThan, MoreThan, Repository } from 'typeorm';

import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { RolesGuard } from '../auth/guards/roles.guard';
import { Roles } from '../auth/decorators/roles.decorator';
import { GetUser } from '../auth/decorators/get-user.decorator';
import {
  CalendarEventEntity,
  EventStatus,
  RescheduleRequestStatus,
  UserEntity,
  UserRole,
} from 'src/database/entities';
import {
  EventParticipantEntity,
  ParticipantRole,
  ParticipantStatus,
} from 'src/database/entities/event-participant.entity';
import { EventRescheduleRequestEntity } from 'src/database/entities/event-reschedule-request.entity';
import { UserAvailabilityEntity } from 'src/database/entities/user-availability.entity';
import { AutoScheduleService } from './auto-schedule.service';
import { AvailabilityService } from './availability.service';
import { CalendarService } from './calendar.service';
import {
  CalendarEventFilterDto,
  CreateCalendarEventDto,
  UpdateCalendarEventDto,
  CreateRescheduleRequestDto,
  ProcessRescheduleRequestDto,
  RespondEventInviteDto,
  SetAvailabilityDto,
} from './dto';

const DEFAULT_RESPONSE_DEADLINE_HOURS = 24;

@ApiTags('Calendar')
@Controller('calendar')
@UseGuards(JwtAuthGuard, RolesGuard)
@ApiBearerAuth()
export class CalendarController {
  constructor(
    @InjectRepository(CalendarEventEntity)
    private readonly calendarRepository: Repository<CalendarEventEntity>,
    @InjectRepository(EventParticipantEntity)
    private readonly participantRepository: Repository<EventParticipantEntity>,
    @InjectRepository(EventRescheduleRequestEntity)
    private readonly rescheduleRepository: Repository<EventRescheduleRequestEntity>,
    @InjectRepository(UserAvailabilityEntity)
    private readonly availabilityRepository: Repository<UserAvailabilityEntity>,
    @InjectRepository(UserEntity)
    private readonly userRepository: Repository<UserEntity>,
    private readonly calendarService: CalendarService,
    private readonly autoScheduleService: AutoScheduleService,
    private readonly availabilityService: AvailabilityService,
  ) {}

  // ===========================================================================
  // EVENTS
  // ===========================================================================

  @Post('events')
  @ApiOperation({ summary: 'Create calendar event' })
  @HttpCode(HttpStatus.CREATED)
  @ApiResponse({ status: HttpStatus.CREATED, description: 'Event created' })
  async createEvent(@Body() dto: CreateCalendarEventDto, @GetUser() user: UserEntity) {
    if (dto.useAutoSchedule) {
      if (!dto.startTime || !dto.endTime) {
        throw new BadRequestException('startTime/endTime are required for auto-schedule range');
      }
      const rangeStart = this.parseDate(dto.startTime, 'startTime');
      const rangeEnd = this.parseDate(dto.endTime, 'endTime');
      if (rangeStart >= rangeEnd) {
        throw new BadRequestException('startTime must be before endTime');
      }

      const participantIds = dto.participantUserIds || [];
      const result = await this.autoScheduleService.autoScheduleEvent({
        eventType: dto.type,
        title: dto.title,
        organizerId: user.id,
        participantIds,
        requiredParticipantIds: participantIds,
        dateRange: { start: rangeStart, end: rangeEnd },
        description: dto.description,
        referenceType: dto.referenceType,
        referenceId: dto.referenceId,
      });

      return {
        success: true,
        message: result.manualRequired ? 'Manual scheduling required' : 'Event auto-scheduled',
        data: result,
      };
    }

    const startTime = this.parseDate(dto.startTime, 'startTime');
    const endTime = this.parseDate(dto.endTime, 'endTime');
    if (startTime >= endTime) {
      throw new BadRequestException('startTime must be before endTime');
    }

    const durationMinutes = this.calculateDurationMinutes(startTime, endTime);
    const participantIds = Array.from(
      new Set((dto.participantUserIds || []).filter((id) => id !== user.id)),
    );
    const allParticipantIds = Array.from(new Set([user.id, ...participantIds]));

    if (allParticipantIds.length > 1) {
      const availability = await this.calendarService.findAvailableSlots({
        userIds: allParticipantIds,
        durationMinutes,
        dateRange: { start: startTime, end: endTime },
        stepMinutes: durationMinutes,
        maxSlots: 1,
      });
      if (
        availability.slots.length === 0 ||
        availability.slots[0].start.getTime() !== startTime.getTime()
      ) {
        throw new BadRequestException('Selected time conflicts with availability');
      }
    }

    const event = this.calendarRepository.create({
      type: dto.type,
      title: dto.title,
      description: dto.description,
      priority: dto.priority,
      startTime,
      endTime,
      durationMinutes,
      organizerId: user.id,
      status: participantIds.length > 0 ? EventStatus.PENDING_CONFIRMATION : EventStatus.SCHEDULED,
      referenceType: dto.referenceType,
      referenceId: dto.referenceId,
      location: dto.location,
      externalMeetingLink: dto.externalMeetingLink,
      reminderMinutes: dto.reminderMinutes,
      notes: dto.notes,
      metadata: dto.metadata,
      isAutoScheduled: false,
    });

    const savedEvent = await this.calendarRepository.save(event);
    const responseDeadline = this.calculateResponseDeadline(startTime);

    const participantEntities: EventParticipantEntity[] = [];
    participantEntities.push(
      this.participantRepository.create({
        eventId: savedEvent.id,
        userId: user.id,
        role: ParticipantRole.ORGANIZER,
        status: ParticipantStatus.ACCEPTED,
        respondedAt: new Date(),
        responseDeadline,
      }),
    );

    for (const participantId of participantIds) {
      participantEntities.push(
        this.participantRepository.create({
          eventId: savedEvent.id,
          userId: participantId,
          role: ParticipantRole.REQUIRED,
          status: ParticipantStatus.PENDING,
          responseDeadline,
        }),
      );
    }

    if (participantEntities.length > 0) {
      await this.participantRepository.save(participantEntities);
    }

    await this.availabilityService.syncCalendarEvents({
      start: startTime,
      end: endTime,
    });

    return {
      success: true,
      message: 'Event created',
      data: {
        event: savedEvent,
        participants: participantEntities,
      },
    };
  }

  @Get('events')
  @ApiOperation({ summary: 'List calendar events' })
  @ApiResponse({ status: HttpStatus.OK, description: 'Events retrieved' })
  async listEvents(@Query() query: CalendarEventFilterDto, @GetUser() user: UserEntity) {
    const qb = this.calendarRepository
      .createQueryBuilder('event')
      .leftJoinAndSelect('event.participants', 'participant');

    if (query.type) {
      qb.andWhere('event.type = :type', { type: query.type });
    }
    if (query.status) {
      qb.andWhere('event.status = :status', { status: query.status });
    }

    const startDate = query.startDate ? this.parseDate(query.startDate, 'startDate') : null;
    const endDate = query.endDate ? this.parseDate(query.endDate, 'endDate') : null;

    if (startDate && endDate) {
      qb.andWhere('event.startTime < :endDate AND event.endTime > :startDate', {
        startDate,
        endDate,
      });
    } else if (startDate) {
      qb.andWhere('event.endTime > :startDate', { startDate });
    } else if (endDate) {
      qb.andWhere('event.startTime < :endDate', { endDate });
    }

    if (query.organizerId) {
      qb.andWhere('event.organizerId = :organizerId', { organizerId: query.organizerId });
    } else if (query.participantId) {
      qb.andWhere('participant.userId = :participantId', { participantId: query.participantId });
    } else {
      qb.andWhere(
        new Brackets((sub) => {
          sub
            .where('event.organizerId = :userId', { userId: user.id })
            .orWhere('participant.userId = :userId', { userId: user.id });
        }),
      );
    }

    const page = query.page && query.page > 0 ? query.page : 1;
    const limit = query.limit && query.limit > 0 ? query.limit : 20;

    qb.orderBy('event.startTime', 'ASC')
      .skip((page - 1) * limit)
      .take(limit);

    const [items, total] = await qb.getManyAndCount();

    return {
      success: true,
      data: {
        items,
        total,
        page,
        limit,
      },
    };
  }

  @Patch('events/:id')
  @ApiOperation({ summary: 'Update calendar event' })
  @HttpCode(HttpStatus.OK)
  @ApiParam({ name: 'id', type: 'string', format: 'uuid' })
  async updateEvent(
    @Param('id', ParseUUIDPipe) id: string,
    @Body() dto: UpdateCalendarEventDto,
    @GetUser() user: UserEntity,
  ) {
    const event = await this.calendarRepository.findOne({ where: { id } });
    if (!event) {
      throw new NotFoundException('Event not found');
    }

    if (
      user.role !== UserRole.ADMIN &&
      user.role !== UserRole.STAFF &&
      event.organizerId !== user.id
    ) {
      throw new ForbiddenException('You are not allowed to update this event');
    }

    if ([EventStatus.CANCELLED, EventStatus.COMPLETED].includes(event.status)) {
      throw new BadRequestException(`Event is ${event.status}, cannot update`);
    }

    const previousStart = event.startTime;
    const previousEnd = event.endTime;

    const startTime = dto.startTime ? this.parseDate(dto.startTime, 'startTime') : event.startTime;
    const endTime = dto.endTime ? this.parseDate(dto.endTime, 'endTime') : event.endTime;
    if (startTime >= endTime) {
      throw new BadRequestException('startTime must be before endTime');
    }

    const durationMinutes = this.calculateDurationMinutes(startTime, endTime);

    await this.calendarRepository.update(event.id, {
      title: dto.title ?? event.title,
      description: dto.description ?? event.description,
      priority: dto.priority ?? event.priority,
      startTime,
      endTime,
      durationMinutes,
      location: dto.location ?? event.location,
      externalMeetingLink: dto.externalMeetingLink ?? event.externalMeetingLink,
      reminderMinutes: dto.reminderMinutes ?? event.reminderMinutes,
      notes: dto.notes ?? event.notes,
    });

    const updated = await this.calendarRepository.findOne({ where: { id: event.id } });

    const rangeStart = previousStart < startTime ? previousStart : startTime;
    const rangeEnd = previousEnd > endTime ? previousEnd : endTime;
    await this.availabilityService.syncCalendarEvents({
      start: rangeStart,
      end: rangeEnd,
    });

    return {
      success: true,
      message: 'Event updated',
      data: updated,
    };
  }

  @Post('events/:id/reschedule')
  @ApiOperation({ summary: 'Request event reschedule' })
  @HttpCode(HttpStatus.OK)
  @ApiParam({ name: 'id', type: 'string', format: 'uuid' })
  async requestReschedule(
    @Param('id', ParseUUIDPipe) eventId: string,
    @Body() dto: CreateRescheduleRequestDto,
    @GetUser() user: UserEntity,
  ) {
    if (dto.eventId && dto.eventId !== eventId) {
      throw new BadRequestException('eventId in body does not match URL');
    }

    const event = await this.calendarRepository.findOne({ where: { id: eventId } });
    if (!event) {
      throw new NotFoundException('Event not found');
    }

    const participants = await this.participantRepository.find({
      where: { eventId },
    });
    const participantIds = participants.map((p) => p.userId);
    const isParticipant = participantIds.includes(user.id) || event.organizerId === user.id;
    if (!isParticipant && user.role !== UserRole.ADMIN && user.role !== UserRole.STAFF) {
      throw new ForbiddenException('You are not allowed to reschedule this event');
    }

    if (dto.proposedTimeSlots && dto.proposedTimeSlots.length > 3) {
      throw new BadRequestException('Maximum 3 proposed time slots allowed');
    }

    if (!dto.useAutoSchedule && (!dto.proposedTimeSlots || dto.proposedTimeSlots.length === 0)) {
      throw new BadRequestException('Provide proposedTimeSlots or enable auto schedule');
    }

    const proposedSlots = dto.proposedTimeSlots?.map((slot) => ({
      start: this.parseDate(slot.start, 'proposedTimeSlots.start'),
      end: this.parseDate(slot.end, 'proposedTimeSlots.end'),
    }));

    const request = this.rescheduleRepository.create({
      eventId,
      requesterId: user.id,
      reason: dto.reason,
      proposedTimeSlots: proposedSlots,
      useAutoSchedule: dto.useAutoSchedule || false,
    });
    const saved = await this.rescheduleRepository.save(request);

    if (!dto.useAutoSchedule) {
      return {
        success: true,
        message: 'Reschedule request submitted',
        data: {
          request: saved,
        },
      };
    }

    const result = await this.autoScheduleService.handleRescheduleRequest(saved.id, user.id);

    return {
      success: true,
      message: result.manualRequired ? 'Manual reschedule required' : 'Reschedule processed',
      data: result,
    };
  }

  @Get('reschedule-requests')
  @Roles(UserRole.STAFF, UserRole.ADMIN)
  @ApiOperation({ summary: 'List reschedule requests' })
  @ApiResponse({ status: HttpStatus.OK, description: 'Reschedule requests retrieved' })
  @ApiQuery({
    name: 'status',
    required: false,
    enum: ['PENDING', 'APPROVED', 'REJECTED', 'AUTO_RESOLVED', 'WITHDRAWN'],
  })
  async listRescheduleRequests(
    @Query('status') status?: string,
    @Query('eventId') eventId?: string,
    @Query('requesterId') requesterId?: string,
    @Query('page') pageRaw?: string,
    @Query('limit') limitRaw?: string,
  ) {
    if (status && !Object.values(RescheduleRequestStatus).includes(status)) {
      throw new BadRequestException('Invalid reschedule request status');
    }

    const qb = this.rescheduleRepository
      .createQueryBuilder('request')
      .leftJoinAndSelect('request.event', 'event')
      .leftJoinAndSelect('request.requester', 'requester')
      .orderBy('request.createdAt', 'DESC');

    if (status) {
      qb.andWhere('request.status = :status', { status });
    }
    if (eventId) {
      qb.andWhere('request.eventId = :eventId', { eventId });
    }
    if (requesterId) {
      qb.andWhere('request.requesterId = :requesterId', { requesterId });
    }

    const page = pageRaw ? Number(pageRaw) : 1;
    const limit = limitRaw ? Number(limitRaw) : 20;
    const safePage = Number.isNaN(page) || page < 1 ? 1 : page;
    const safeLimit = Number.isNaN(limit) || limit < 1 ? 20 : limit;

    qb.skip((safePage - 1) * safeLimit).take(safeLimit);

    const [items, total] = await qb.getManyAndCount();
    const safeItems = items.map((request) => ({
      id: request.id,
      eventId: request.eventId,
      requesterId: request.requesterId,
      reason: request.reason,
      proposedTimeSlots: request.proposedTimeSlots || [],
      useAutoSchedule: request.useAutoSchedule,
      status: request.status,
      processedById: request.processedById,
      processedAt: request.processedAt,
      processNote: request.processNote,
      newEventId: request.newEventId,
      selectedNewStartTime: request.selectedNewStartTime,
      createdAt: request.createdAt,
      event: request.event
        ? {
            id: request.event.id,
            title: request.event.title,
            startTime: request.event.startTime,
            endTime: request.event.endTime,
            status: request.event.status,
            type: request.event.type,
            organizerId: request.event.organizerId,
            referenceType: request.event.referenceType,
            referenceId: request.event.referenceId,
          }
        : null,
      requester: request.requester
        ? {
            id: request.requester.id,
            fullName: request.requester.fullName,
            email: request.requester.email,
            role: request.requester.role,
          }
        : null,
    }));

    return {
      success: true,
      data: {
        items: safeItems,
        total,
        page: safePage,
        limit: safeLimit,
      },
    };
  }

  @Post('reschedule-requests/process')
  @Roles(UserRole.STAFF, UserRole.ADMIN)
  @ApiOperation({ summary: 'Process reschedule request' })
  @HttpCode(HttpStatus.OK)
  async processRescheduleRequest(
    @Body() dto: ProcessRescheduleRequestDto,
    @GetUser() user: UserEntity,
  ) {
    const request = await this.rescheduleRepository.findOne({
      where: { id: dto.requestId },
    });
    if (!request) {
      throw new NotFoundException('Reschedule request not found');
    }

    if (request.status !== RescheduleRequestStatus.PENDING) {
      throw new BadRequestException('Reschedule request already processed');
    }

    if (!['approve', 'reject'].includes(dto.action)) {
      throw new BadRequestException('Invalid reschedule action');
    }

    if (dto.action === 'reject') {
      await this.rescheduleRepository.update(request.id, {
        status: RescheduleRequestStatus.REJECTED,
        processedById: user.id,
        processedAt: new Date(),
        processNote: dto.processNote,
      });

      return {
        success: true,
        message: 'Reschedule request rejected',
        data: { id: request.id, status: RescheduleRequestStatus.REJECTED },
      };
    }

    if (dto.selectedNewStartTime) {
      const result = await this.autoScheduleService.processManualRescheduleRequest(
        request.id,
        new Date(dto.selectedNewStartTime),
        user.id,
        dto.processNote,
      );

      return {
        success: true,
        message: result.manualRequired ? 'Manual reschedule required' : 'Reschedule approved',
        data: result,
      };
    }

    const result = await this.autoScheduleService.handleRescheduleRequest(request.id, user.id);

    return {
      success: true,
      message: result.manualRequired ? 'Manual reschedule required' : 'Reschedule approved',
      data: result,
    };
  }

  @Post('events/:id/respond')
  @ApiOperation({ summary: 'Respond to event invitation' })
  @HttpCode(HttpStatus.OK)
  @ApiParam({ name: 'id', type: 'string', format: 'uuid' })
  async respondInvite(
    @Param('id', ParseUUIDPipe) eventId: string,
    @Body() dto: RespondEventInviteDto,
    @GetUser() user: UserEntity,
  ) {
    const participant = await this.participantRepository.findOne({
      where: { id: dto.participantId },
    });
    if (!participant) {
      throw new NotFoundException('Participant not found');
    }
    if (participant.eventId !== eventId) {
      throw new BadRequestException('participantId does not belong to this event');
    }
    if (
      participant.userId !== user.id &&
      user.role !== UserRole.ADMIN &&
      user.role !== UserRole.STAFF
    ) {
      throw new ForbiddenException('You are not allowed to respond for this invitation');
    }

    const result = await this.autoScheduleService.processEventInvitations(
      dto.participantId,
      dto.response,
      dto.responseNote,
    );

    return {
      success: true,
      message: 'Response recorded',
      data: result,
    };
  }

